<div class="d-flex justify-content-between align-items-start mb-4"><div><h1 class="h3 mb-1">Map Providers</h1><p class="text-muted mb-0">Configure address geocoding for properties and future route planning.</p></div><a class="btn btn-outline-primary" href="/portal/map"><i class="fa-solid fa-map-location-dot me-2"></i>Operations Map</a></div>
<div class="row g-3 mb-4"><?php foreach(['total'=>'Properties','pending'=>'Pending','geocoded'=>'Geocoded','verified'=>'Verified','failed'=>'Failed'] as $key=>$label):?><div class="col-6 col-lg"><div class="card card-body"><small class="text-muted"><?=e($label)?></small><strong class="fs-3"><?=number_format((int)($stats[$key]??0))?></strong></div></div><?php endforeach?></div>
<div class="row g-4"><div class="col-lg-7"><div class="card"><div class="card-body"><h2 class="h5">Provider settings</h2><form method="post" action="/portal/map-providers" class="row g-3"><?=csrf_field()?><div class="col-md-6"><label class="form-label">Primary provider</label><select name="provider" class="form-select"><option value="nominatim" <?=($settings['provider']??'')==='nominatim'?'selected':''?>>OpenStreetMap / Nominatim</option><option value="google" <?=($settings['provider']??'')==='google'?'selected':''?>>Google Maps Geocoding</option><option value="disabled" <?=($settings['provider']??'')==='disabled'?'selected':''?>>Disabled</option></select></div><div class="col-md-6"><label class="form-label">Fallback provider</label><select name="fallback_provider" class="form-select"><option value="none">None</option><option value="nominatim" <?=($settings['fallback_provider']??'')==='nominatim'?'selected':''?>>Nominatim</option><option value="google" <?=($settings['fallback_provider']??'')==='google'?'selected':''?>>Google</option></select></div><div class="col-md-4"><label class="form-label">Cache days</label><input class="form-control" type="number" min="1" max="3650" name="cache_days" value="<?=e($settings['cache_days']??180)?>"></div><div class="col-md-4"><label class="form-label">Requests / second</label><input class="form-control" type="number" min="1" max="10" name="requests_per_second" value="<?=e($settings['requests_per_second']??1)?>"></div><div class="col-md-4 d-flex align-items-end"><div class="form-check mb-2"><input class="form-check-input" type="checkbox" name="active" id="maps-active" <?=!empty($settings['active'])?'checked':''?>><label class="form-check-label" for="maps-active">Geocoding enabled</label></div></div><div class="col-md-6"><label class="form-label">Nominatim user agent</label><input class="form-control" name="user_agent" value="<?=e($settings['user_agent']??'ServiceOS/0.32.1')?>"></div><div class="col-md-6"><label class="form-label">Contact email</label><input class="form-control" type="email" name="contact_email" value="<?=e($settings['contact_email']??'')?>"><div class="form-text">Recommended for responsible Nominatim use.</div></div><div class="col-12"><div class="alert <?=$googleConfigured?'alert-success':'alert-secondary'?> mb-0">Google API key: <strong><?=$googleConfigured?'configured':'not configured'?></strong>. Set <code>GOOGLE_MAPS_API_KEY</code> in <code>.env</code> to enable Google.</div></div><div class="col-12"><button class="btn btn-primary">Save settings</button></div></form></div></div></div><div class="col-lg-5"><div class="card"><div class="card-body"><h2 class="h5">Test geocoding</h2><form method="post" action="/portal/map-providers/test"><?=csrf_field()?><label class="form-label">Address</label><textarea class="form-control" name="address" rows="3" required>102 Main Street, Plattsmouth, NE 68048, USA</textarea><button class="btn btn-outline-primary mt-3">Run test</button></form></div></div></div></div>
<div class="card mt-4"><div class="card-header"><strong>Recent property geocoding status</strong></div><div class="table-responsive"><table class="table table-hover mb-0"><thead><tr><th>Customer</th><th>Property</th><th>Status</th><th>Source</th><th>Last attempt</th><th></th></tr></thead><tbody><?php foreach($recent as $row):?><tr><td><?=e($row['display_name'])?></td><td><?=e($row['label'])?><br><small class="text-muted"><?=e($row['address1'].', '.$row['city'].', '.$row['state'].' '.$row['postal_code'])?></small><?php if(!empty($row['geocode_error'])):?><div class="small text-danger"><?=e($row['geocode_error'])?></div><?php endif?></td><td><span class="badge text-bg-<?=in_array($row['geocode_status'],['geocoded','verified'],true)?'success':($row['geocode_status']==='failed'?'danger':'secondary')?>"><?=e($row['geocode_status']?:'pending')?></span></td><td><?=e($row['geocode_source']??'')?></td><td><?=e($row['geocoded_at']??'Never')?></td><td><a class="btn btn-sm btn-outline-secondary" href="/portal/properties/<?=$row['id']?>/edit">Open</a></td></tr><?php endforeach;if(!$recent):?><tr><td colspan="6" class="text-center text-muted py-4">No properties found.</td></tr><?php endif?></tbody></table></div></div>
